"use client";

import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';

export interface GhostEtherProps {
  mouseForce?: number;
  cursorSize?: number;
  isViscous?: boolean;
  viscous?: number;
  iterationsViscous?: number;
  iterationsPoisson?: number;
  dt?: number;
  BFECC?: boolean;
  resolution?: number;
  isBounce?: boolean;
  colors?: string[];
  style?: React.CSSProperties;
  className?: string;
  autoDemo?: boolean;
  autoSpeed?: number;
  autoIntensity?: number;
  takeoverDuration?: number;
  autoResumeDelay?: number;
  autoRampDuration?: number;
}

const defaultColors = ['#7B2CBF', '#3F37C9', '#00F5D4'];

const vertexShader = `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = vec4(position, 1.0);
  }
`;

const fragmentShader = `
  uniform vec2 uResolution;
  uniform float uTime;
  uniform float uAutoSpeed;
  uniform vec2 uMouse;
  uniform float uMouseForce;
  uniform vec3 uColor1;
  uniform vec3 uColor2;
  uniform vec3 uColor3;
  varying vec2 vUv;

  float hash(vec2 p) {
    p = fract(p * vec2(123.34, 456.21));
    p += dot(p, p + 45.32);
    return fract(p.x * p.y);
  }

  float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
  }

  float fbm(vec2 p) {
    float v = 0.0;
    float a = 0.5;
    vec2 shift = vec2(100.0);
    mat2 rot = mat2(cos(0.5), sin(0.5), -sin(0.5), cos(0.5));
    for (int i = 0; i < 4; ++i) {
      v += a * noise(p);
      p = rot * p * 2.0 + shift;
      a *= 0.5;
    }
    return v;
  }

  void main() {
    vec2 uv = vUv;
    vec2 p = uv * 3.0;
    float t = uTime * uAutoSpeed;

    // Interaction
    vec2 toMouse = uv - uMouse;
    toMouse.x *= uResolution.x / uResolution.y;
    float dist = length(toMouse);
    float influence = smoothstep(0.5, 0.0, dist);

    // Warp coordinates locally
    p += toMouse * influence * uMouseForce * 2.0;

    vec2 q = vec2(
      fbm(p + vec2(t * 0.15, t * 0.1)),
      fbm(p + vec2(5.2, 1.3) + vec2(-t * 0.1, t * 0.15))
    );

    vec2 r = vec2(
      fbm(p + 4.0 * q + vec2(1.7, 9.2) + vec2(t * 0.05, -t * 0.08)),
      fbm(p + 4.0 * q + vec2(8.3, 2.8) + vec2(-t * 0.07, t * 0.03))
    );

    float f = fbm(p + 4.0 * r);

    // Dynamic color shifting LFO (breathing colors)
    float lfo = sin(uTime * 0.08) * 0.5 + 0.5;
    vec3 c1 = mix(uColor1, uColor2, lfo * 0.4);
    vec3 c2 = mix(uColor2, uColor3, (1.0 - lfo) * 0.4);
    vec3 c3 = mix(uColor3, uColor1, lfo * 0.3);

    vec3 col = mix(c1, c2, clamp(f * f * 4.0, 0.0, 1.0));
    col = mix(col, c3, clamp(length(q), 0.0, 1.0));

    // Highlight
    col += vec3(0.05, 0.1, 0.15) * length(r);

    // Muted vignette
    float vignette = uv.x * uv.y * (1.0 - uv.x) * (1.0 - uv.y);
    vignette = clamp(pow(16.0 * vignette, 0.2), 0.0, 1.0);
    col *= vignette;

    gl_FragColor = vec4(col, 1.0);
  }
`;

export default function GhostEther({
  mouseForce = 20,
  cursorSize = 75,
  resolution = 0.5,
  colors = defaultColors,
  style = {},
  className = '',
  autoDemo = true,
  autoSpeed = 0.5,
  autoIntensity = 2.2,
  takeoverDuration = 0.25,
  autoResumeDelay = 2000,
  autoRampDuration = 0.6
}: GhostEtherProps): React.ReactElement {
  const mountRef = useRef<HTMLDivElement | null>(null);
  const containerRef = useRef<{
    renderer?: THREE.WebGLRenderer;
    scene?: THREE.Scene;
    camera?: THREE.OrthographicCamera;
    material?: THREE.ShaderMaterial;
    mesh?: THREE.Mesh;
    rafId?: number;
    resizeObserver?: ResizeObserver;
    intersectionObserver?: IntersectionObserver;
    isVisible: boolean;
  }>({ isVisible: true });

  const mouseStateRef = useRef({
    current: new THREE.Vector2(0.5, 0.5),
    target: new THREE.Vector2(0.5, 0.5),
    velocity: 0,
    targetVelocity: 0,
    lastTime: performance.now(),
    lastPosition: new THREE.Vector2(0.5, 0.5),
    isHovered: false,
    lastInteraction: performance.now()
  });

  const autoWanderRef = useRef({
    target: new THREE.Vector2(0.5, 0.5),
    lastWanderTime: 0
  });

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    // 1. Setup Three.js Context
    const rect = mount.getBoundingClientRect();
    const width = rect.width || 300;
    const height = rect.height || 300;

    const renderer = new THREE.WebGLRenderer({ antialias: false, alpha: true });
    renderer.setSize(width * resolution, height * resolution, false);
    renderer.setPixelRatio(1);

    const canvas = renderer.domElement;
    canvas.style.width = '100%';
    canvas.style.height = '100%';
    canvas.style.display = 'block';
    mount.appendChild(canvas);

    const scene = new THREE.Scene();
    const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);

    const col1 = new THREE.Color(colors[0] || defaultColors[0]);
    const col2 = new THREE.Color(colors[1] || defaultColors[1]);
    const col3 = new THREE.Color(colors[2] || defaultColors[2]);

    const material = new THREE.ShaderMaterial({
      vertexShader,
      fragmentShader,
      uniforms: {
        uResolution: { value: new THREE.Vector2(width * resolution, height * resolution) },
        uTime: { value: 0 },
        uAutoSpeed: { value: autoSpeed },
        uMouse: { value: new THREE.Vector2(0.5, 0.5) },
        uMouseForce: { value: 0 },
        uColor1: { value: col1 },
        uColor2: { value: col2 },
        uColor3: { value: col3 }
      },
      depthWrite: false,
      depthTest: false
    });

    const geometry = new THREE.PlaneGeometry(2, 2);
    const mesh = new THREE.Mesh(geometry, material);
    scene.add(mesh);

    const state = containerRef.current;
    state.renderer = renderer;
    state.scene = scene;
    state.camera = camera;
    state.material = material;
    state.mesh = mesh;

    // 2. Event Listeners
    const mouseState = mouseStateRef.current;
    const handleMouseMove = (e: MouseEvent) => {
      const bound = mount.getBoundingClientRect();
      const x = (e.clientX - bound.left) / bound.width;
      const y = 1.0 - (e.clientY - bound.top) / bound.height;

      if (x >= 0 && x <= 1 && y >= 0 && y <= 1) {
        mouseState.target.set(x, y);
        mouseState.isHovered = true;
        mouseState.lastInteraction = performance.now();
      } else {
        mouseState.isHovered = false;
      }
    };

    const handleTouchMove = (e: TouchEvent) => {
      if (e.touches.length === 0) return;
      const bound = mount.getBoundingClientRect();
      const x = (e.touches[0].clientX - bound.left) / bound.width;
      const y = 1.0 - (e.touches[0].clientY - bound.top) / bound.height;

      if (x >= 0 && x <= 1 && y >= 0 && y <= 1) {
        mouseState.target.set(x, y);
        mouseState.isHovered = true;
        mouseState.lastInteraction = performance.now();
      }
    };

    const handleMouseLeave = () => {
      mouseState.isHovered = false;
    };

    const doc = mount.ownerDocument || document;
    doc.addEventListener('mousemove', handleMouseMove);
    mount.addEventListener('touchmove', handleTouchMove, { passive: true });
    mount.addEventListener('mouseleave', handleMouseLeave);

    // 3. Animation Loop
    const clock = new THREE.Clock();

    const animate = () => {
      if (!state.isVisible) {
        state.rafId = requestAnimationFrame(animate);
        return;
      }

      const now = performance.now();
      const dt = Math.max(1, now - mouseState.lastTime);
      mouseState.lastTime = now;

      // Auto wandering logic when idle
      if (autoDemo && (!mouseState.isHovered || now - mouseState.lastInteraction > autoResumeDelay)) {
        const wander = autoWanderRef.current;
        if (now - wander.lastWanderTime > 3000) {
          wander.target.set(0.2 + Math.random() * 0.6, 0.2 + Math.random() * 0.6);
          wander.lastWanderTime = now;
        }
        mouseState.target.lerp(wander.target, 0.02);
        mouseState.targetVelocity = 0.15;
      } else {
        // Calculate speed based on distance moved
        const dist = mouseState.current.distanceTo(mouseState.lastPosition);
        mouseState.lastPosition.copy(mouseState.current);
        mouseState.targetVelocity = dist / (dt / 1000);
      }

      // Smooth mouse position and velocity
      mouseState.current.lerp(mouseState.target, 0.08);
      mouseState.velocity += (mouseState.targetVelocity - mouseState.velocity) * 0.05;
      mouseState.velocity *= 0.95; // Decay velocity

      // Update uniforms
      if (material) {
        material.uniforms.uTime.value = clock.getElapsedTime();
        material.uniforms.uMouse.value.copy(mouseState.current);
        material.uniforms.uMouseForce.value = mouseState.velocity * (mouseForce * 0.01);
      }

      renderer.render(scene, camera);
      state.rafId = requestAnimationFrame(animate);
    };

    clock.start();
    animate();

    // 4. Resize and Intersection Observers
    const resizeObserver = new ResizeObserver((entries) => {
      const entry = entries[0];
      if (!entry) return;
      const w = entry.contentRect.width || 300;
      const h = entry.contentRect.height || 300;
      renderer.setSize(w * resolution, h * resolution, false);
      if (material) {
        material.uniforms.uResolution.value.set(w * resolution, h * resolution);
      }
    });
    resizeObserver.observe(mount);
    state.resizeObserver = resizeObserver;

    const intersectionObserver = new IntersectionObserver((entries) => {
      const entry = entries[0];
      state.isVisible = entry.isIntersecting;
    }, { threshold: 0 });
    intersectionObserver.observe(mount);
    state.intersectionObserver = intersectionObserver;

    // 5. Cleanup
    return () => {
      if (state.rafId) cancelAnimationFrame(state.rafId);

      doc.removeEventListener('mousemove', handleMouseMove);
      mount.removeEventListener('touchmove', handleTouchMove);
      mount.removeEventListener('mouseleave', handleMouseLeave);

      if (state.resizeObserver) state.resizeObserver.disconnect();
      if (state.intersectionObserver) state.intersectionObserver.disconnect();

      if (renderer) {
        if (canvas.parentNode) {
          canvas.parentNode.removeChild(canvas);
        }
        renderer.dispose();
      }

      geometry.dispose();
      material.dispose();
    };
  }, [resolution, colors, autoDemo, autoSpeed, autoResumeDelay, mouseForce]);

  // Handle dynamic prop updates
  useEffect(() => {
    const state = containerRef.current;
    if (state.material) {
      state.material.uniforms.uAutoSpeed.value = autoSpeed;
      state.material.uniforms.uColor1.value.set(colors[0] || defaultColors[0]);
      state.material.uniforms.uColor2.value.set(colors[1] || defaultColors[1]);
      state.material.uniforms.uColor3.value.set(colors[2] || defaultColors[2]);
    }
  }, [autoSpeed, colors]);

  return (
    <div
      ref={mountRef}
      className={`w-full h-full relative overflow-hidden pointer-events-none touch-none ${className}`}
      style={style}
    />
  );
}
